import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const GoldSilverContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
`;

const PageTitle = styled(motion.h1)`
  font-size: 2.5rem;
  margin-bottom: 2rem;
  text-align: center;
  background: linear-gradient(45deg, #ffd700, #c0c0c0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const MetalsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const MetalCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  text-align: center;
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
  }
`;

const MetalIcon = styled.div`
  font-size: 3rem;
  margin-bottom: 1rem;
`;

const MetalName = styled.h3`
  font-size: 1.5rem;
  margin-bottom: 1rem;
  color: #ffffff;
`;

const MetalPrice = styled.div`
  font-size: 2rem;
  font-weight: bold;
  margin-bottom: 0.5rem;
  color: #ffd700;
`;

const MetalChange = styled.div<{ positive: boolean }>`
  color: ${props => props.positive ? '#4ecdc4' : '#ff6b6b'};
  font-size: 1.1rem;
  margin-bottom: 1rem;
`;

const MetalInfo = styled.p`
  color: #cccccc;
  line-height: 1.6;
`;

const metalsData = [
  {
    name: 'Gold',
    icon: 'ðŸ¥‡',
    price: '$2,150.75',
    change: '+2.5%',
    positive: true,
    info: '24K gold per ounce. Safe-haven asset with strong demand.'
  },
  {
    name: 'Silver',
    icon: 'ðŸ¥ˆ',
    price: '$25.80',
    change: '+1.2%',
    positive: true,
    info: 'Spot price per ounce. Industrial and investment demand growing.'
  },
  {
    name: 'Platinum',
    icon: 'ðŸ”·',
    price: '$950.30',
    change: '-0.8%',
    positive: false,
    info: 'Rare industrial metal with automotive applications.'
  },
  {
    name: 'Palladium',
    icon: 'ðŸ”¶',
    price: '$1,120.45',
    change: '+0.5%',
    positive: true,
    info: 'Automotive catalyst metal with limited supply.'
  }
];

const GoldSilver: React.FC = () => {
  return (
    <GoldSilverContainer>
      <PageTitle
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        ðŸ’° Precious Metals
      </PageTitle>

      <MetalsGrid>
        {metalsData.map((metal, index) => (
          <MetalCard
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            whileHover={{ scale: 1.02 }}
          >
            <MetalIcon>{metal.icon}</MetalIcon>
            <MetalName>{metal.name}</MetalName>
            <MetalPrice>{metal.price}</MetalPrice>
            <MetalChange positive={metal.positive}>
              {metal.change} {metal.positive ? 'ðŸ“ˆ' : 'ðŸ“‰'}
            </MetalChange>
            <MetalInfo>{metal.info}</MetalInfo>
          </MetalCard>
        ))}
      </MetalsGrid>

      <motion.div
        style={{ marginTop: '3rem', textAlign: 'center' }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.8 }}
      >
        <h3>ðŸ“Š Market Overview</h3>
        <p style={{ color: '#cccccc', maxWidth: '600px', margin: '0 auto' }}>
          Precious metals continue to show strength as investors seek diversification 
          and protection against market volatility. Gold and silver remain popular 
          choices for long-term wealth preservation.
        </p>
      </motion.div>
    </GoldSilverContainer>
  );
};

export default GoldSilver;
